const items = $input.all();
const today = new Date();
const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
const todayStr = yyyy + '-' + mm + '-' + dd;

const pending = items.map((item, index) => {
  return { 
    ...item.json, 
    sheet_row: index + 2
  };
}).filter(r => {
  const rowDate = (r.date || '').toString().trim();
  const rowStatus = (r.status || '').toString().trim().toLowerCase();
  return rowStatus === 'pending' && rowDate <= todayStr && rowDate !== '';
});

if (pending.length === 0) {
  return [{ json: { nothingToDo: true, todayStr, rows: [] } }];
}
return [{ json: { nothingToDo: false, todayStr, rows: pending } }];

const d = $input.first().json;
if (d.nothingToDo || !d.rows || d.rows.length === 0) return [];

const allSessions = $getWorkflowStaticData('global');
allSessions.__loopResults = [];

return d.rows.map(r => ({ json: r }));

const row = $input.first().json;
const rowDate = (row.date || new Date().toISOString().slice(0, 10)).trim();
let startedISO = rowDate + 'T09:00:00.000+0000';

if (row.started_at) {
  try {
    const timeStr = row.started_at.toString().trim();
    const combined = rowDate + 'T' + timeStr + ':00.000+0000';
    const parsed = new Date(combined);
    if (!isNaN(parsed)) {
      startedISO = parsed.toISOString().replace('Z', '+0000');
    } else {
      const parsed2 = new Date(rowDate + ' ' + timeStr);
      if (!isNaN(parsed2)) startedISO = parsed2.toISOString().replace('Z', '+0000');
    }
  } catch(e) {}
}

let timeSpent = '1h';
if (row.log_time) {
  const raw = row.log_time.toString().trim().toLowerCase();
  if (/^\d+h(\d+m)?$/.test(raw))  { timeSpent = raw; }
  else if (/^\d+m$/.test(raw))      { timeSpent = raw; }
  else if (/^[\d.]+$/.test(raw))    {
    const hrs = parseFloat(raw);
    const h = Math.floor(hrs);
    const m = Math.round((hrs - h) * 60);
    timeSpent = h > 0 ? (h + 'h' + (m > 0 ? m + 'm' : '')) : m + 'm';
  }
}

const payload = { ...row, jiraIssueKey: row.ticket_id, rowDate, timeSpent, startedISO, logComment: row.log_text || 'Daily worklog' };

const allSessions = $getWorkflowStaticData('global');
allSessions.__currentRow = { ticket_id: row.ticket_id, date: row.date, timeSpent, log_text: row.log_text || '', retry_count: parseInt(row.retry_count || 0), row_number: row.row_number };

return [{ json: payload }];

const jiraResp = $input.first().json;
const allSessions = $getWorkflowStaticData('global');
const rowData = allSessions.__currentRow || {};

const isSuccess = !!(jiraResp.id || jiraResp.self);

const result = {
  sheet_row:     rowData.row_number || rowData.sheet_row, 
  status:        isSuccess ? 'Completed' : 'Pending',
  error_message: isSuccess ? '' : JSON.stringify(jiraResp).slice(0, 200),
  retry_count:   isSuccess ? 0 : (rowData.retry_count + 1),
  jiraSuccess:   isSuccess,
  ticket_id:     rowData.ticket_id,
  timeSpent:     rowData.timeSpent,
};

if (!allSessions.__loopResults) allSessions.__loopResults = [];
allSessions.__loopResults.push(result);

return [{ json: result }];

const allSessions = $getWorkflowStaticData('global');
const results = allSessions.__loopResults || [];
allSessions.__loopResults = [];

let success = 0, failed = 0, totalMinutes = 0;
const failedTickets = [];
const ticketIds = [];

for (const item of results) {
  if (item.ticket_id) { ticketIds.push(item.ticket_id); }
  if (item.jiraSuccess === true) {
    success++;
    const ts = item.timeSpent || '0m';
    const h = ts.match(/(\d+)h/) ? parseInt(ts.match(/(\d+)h/)[1]) : 0;
    const m = ts.match(/(\d+)m/) ? parseInt(ts.match(/(\d+)m/)[1]) : 0;
    totalMinutes += (h * 60) + m;
  } else {
    failed++;
    failedTickets.push(item.ticket_id + ' (' + item.date + ')');
  }
}

const h = Math.floor(totalMinutes / 60);
const m = totalMinutes % 60;
const totalStr = h > 0 ? h + 'h ' + (m > 0 ? m + 'm' : '') : m + 'm';

return [{ json: { success, failed, totalStr: totalStr.trim() || '0m', today: new Date().toISOString().slice(0, 10), failedTickets: failedTickets.join(', ') || 'None', ticket_ids: ticketIds.join(', ') } }];
